"use client";
import * as React from "react";
import { alertAnatomy } from "@tessera/core";

export type AlertType = "info" | "success" | "warning" | "danger";

export interface AlertProps extends React.HTMLAttributes<HTMLDivElement> {
  type?: AlertType;
  title: string;
  /** Optional supporting text below the title. */
  description?: string;
  /** Custom leading icon; a default per-type glyph is rendered otherwise. */
  icon?: React.ReactNode;
}

const defaultGlyphs: Record<AlertType, string> = {
  info: "ℹ",
  success: "✓",
  warning: "⚠",
  danger: "✕",
};

export const Alert = React.forwardRef<HTMLDivElement, AlertProps>(function Alert(
  { type = "info", title, description, icon, children, ...rest },
  ref
) {
  // Interruptive types announce assertively; informational ones politely.
  const role = type === "danger" || type === "warning" ? "alert" : "status";
  return (
    <div {...alertAnatomy.attrs("root")} data-type={type} role={role} ref={ref} {...rest}>
      <span {...alertAnatomy.attrs("icon")} aria-hidden>
        {icon ?? defaultGlyphs[type]}
      </span>
      <div {...alertAnatomy.attrs("title")}>{title}</div>
      {(description || children) && (
        <div {...alertAnatomy.attrs("description")}>{description ?? children}</div>
      )}
    </div>
  );
});

@layer tessera.recipes {
  [data-scope="alert"][data-part="root"] {
    --alert-accent: var(--ts-accent-default);
    --alert-bg: var(--ts-accent-subtle);
    --alert-fg: var(--ts-accent-fg);

    display: grid;
    grid-template-columns: auto 1fr;
    column-gap: var(--ts-space-3);
    row-gap: var(--ts-space-1);
    align-items: start;
    border: 1px solid var(--ts-border-muted);
    border-left: 3px solid var(--alert-accent);
    border-radius: var(--ts-radius-lg);
    background: var(--alert-bg);
    padding: var(--ts-space-3) var(--ts-space-4);
  }

  [data-scope="alert"][data-part="root"][data-type="success"] {
    --alert-accent: var(--ts-success-default);
    --alert-bg: var(--ts-success-subtle);
    --alert-fg: var(--ts-success-fg);
  }

  [data-scope="alert"][data-part="root"][data-type="warning"] {
    --alert-accent: var(--ts-warning-default);
    --alert-bg: var(--ts-warning-subtle);
    --alert-fg: var(--ts-warning-fg);
  }

  [data-scope="alert"][data-part="root"][data-type="danger"] {
    --alert-accent: var(--ts-danger-default);
    --alert-bg: var(--ts-danger-subtle);
    --alert-fg: var(--ts-danger-fg);
  }

  [data-scope="alert"][data-part="icon"] {
    display: inline-flex;
    color: var(--alert-fg);
    margin-top: 2px;
    grid-row: span 2;
  }

  [data-scope="alert"][data-part="title"] {
    font-size: var(--ts-font-size-sm);
    font-weight: var(--ts-font-weight-semibold);
    color: var(--alert-fg);
  }

  [data-scope="alert"][data-part="description"] {
    grid-column: 2;
    font-size: var(--ts-font-size-sm);
    color: var(--ts-fg-muted);
    line-height: var(--ts-font-leading-normal);
  }
}
